    "public Object set(int index, Object object) {
        int pos = indexOf(object);
        Object removed = super.set(index, object);

        if (pos == -1) {
            // new object not previously present: update the backing set
            set.remove(removed);
            set.add(object);
            return removed;
        }
        if (pos == index) {
            // setting the same value at the same position; nothing else to do
            return removed;
        }

        // object existed elsewhere; remove the duplicate occurrence
        super.remove(pos);
        // the old element at 'index' was removed by the set operation, so update the set
        set.remove(removed);

        return removed;
    }"
  ],
  "additional_testcases": [
    {
      "path": "org/apache/commons/collections/list/TestSetUniqueList.java",
      "testcase": "public void testSetReplacesWithExistingElementAndUpdatesSet() {
        List list = new LinkedList();
        SetUniqueList decoratedList = SetUniqueList.decorate(list);
        String a = "A";
        String b = "B";
        String c = "C";

        decoratedList.add(a);
        decoratedList.add(b);
        decoratedList.add(c);
        assertEquals(3, decoratedList.size());

        // Replace index 2 (C) with existing element A (at index 0)
        decoratedList.set(2, a);
        // Should remove the old A at index 0 to keep uniqueness
        assertEquals(2, decoratedList.size());
        assertTrue(decoratedList.contains(a));
        assertTrue(decoratedList.contains(b));
        assertFalse(decoratedList.contains(c));

        // Adding C back should be allowed and increase size
        decoratedList.add(c);
        assertEquals(3, decoratedList.size());

        // Adding A again should not increase size
        decoratedList.add(a);
        assertEquals(3, decoratedList.size());
    }"
    }
  ]
}

